// Taysīr al-ʿAzīz al-Ḥamīd - Données complètes des 66 chapitres
// Auteur : Sulaymān ibn ʿAbdillāh ibn Muḥammad ibn ʿAbd al-Wahhāb
// Adaptation française basée sur le sharh

const CHAPTERS = [
  {id:1, arNum:"الباب الأول", arTitle:"باب فضل التوحيد وما يكفر من الذنوب", frTitle:"Le mérite du Tawḥīd et les péchés qu'il efface", summary:"Ce chapitre établit la place centrale du Tawḥīd dans l'Islam. Le Tawḥīd est la plus grande des obligations et la base de toute œuvre. L'auteur cite la parole d'Allah : « Ceux qui ont cru et n'ont point voilé leur foi par de l'injustice (shirk), ceux-là ont la sécurité et ils sont bien-guidés » (6:82). Les Compagnons ont compris que « l'injustice » ici désigne le shirk. Le Prophète ﷺ a dit : « Quiconque dit : il n'y a de divinité qu'Allah, et mécroit en ce qui est adoré en dehors d'Allah, ses biens et son sang sont inviolables. » Le Tawḥīd est donc la clé du Paradis et l'effaceur des péchés.", verses:[{ar:"الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُم بِظُلْمٍ أُولَٰئِكَ لَهُمُ الْأَمْنُ وَهُم مُّهْتَدُونَ",fr:"Ceux qui ont cru et n'ont point voilé leur foi par de l'injustice (shirk), ceux-là ont la sécurité et ils sont bien-guidés.",ref:"Sourate al-Anʿām (6:82)"},{ar:"وَاعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا",fr:"Adorez Allah et ne Lui associez rien.",ref:"Sourate an-Nisāʾ (4:36)"},{ar:"إِنَّ اللَّهَ لَا يَغْفِرُ أَنْ يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَنْ يَشَاءُ",fr:"Certes, Allah ne pardonne pas qu'on Lui associe quoi que ce soit ; et Il pardonne ce qui est moins que cela à qui Il veut.",ref:"Sourate an-Nisāʾ (4:48)"}],hadiths:[{ar:"عَنْ عُبَادَةَ بْنِ الصَّامِتِ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «مَنْ قَالَ: لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ، وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ، وَأَنَّ عِيسَى عَبْدُ اللَّهِ وَرَسُولُهُ... فَإِنَّ اللَّهَ يُدْخِلُهُ الْجَنَّةَ»",fr:"Quiconque atteste qu'il n'y a de divinité qu'Allah, Seul sans associé, que Muḥammad est Son serviteur et messager, qu'Issā est le serviteur d'Allah et Son messager... Allah le fera entrer au Paradis.",ref:"Rapporté par al-Bukhārī"}]},
  {id:2, arNum:"الباب الثاني", arTitle:"باب من حقق التوحيد دخل الجنة بغير حساب", frTitle:"Celui qui réalise pleinement le Tawḥīd entre au Paradis sans jugement", summary:"Ce chapitre traite des soixante-dix mille personnes qui entreront au Paradis sans jugement ni châtiment. Le Prophète ﷺ a décrit ces gens comme ceux qui ne pratiquent pas la ruqya (incantations), ne se font pas cautériser, ne croient pas aux mauvais augures, et placent leur entière confiance en leur Seigneur. L'auteur commente que la réalisation parfaite du Tawḥīd purifie le cœur de toute attache à autre qu'Allah, ce qui est la clé de l'entrée au Paradis sans compte. La confiance absolue (tawakkul) est la manifestation la plus élevée de cette réalisation du Tawḥīd.", verses:[{ar:"إِنَّمَا الْمُؤْمِنُونَ الَّذِينَ إِذَا ذُكِرَ اللَّهُ وَجِلَتْ قُلُوبُهُمْ",fr:"Les vrais croyants sont ceux dont les cœurs frémissent quand on mentionne Allah.",ref:"Sourate al-Anfāl (8:2)"}],hadiths:[{ar:"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «عُرِضَتْ عَلَيَّ الْأُمَمُ، فَرَأَيْتُ النَّبِيَّ وَمَعَهُ الرَّهْطُ، وَالنَّبِيَّ وَمَعَهُ الرَّجُلُ وَالنَّبِيَّ وَمَعَهُ الرَّجُلَانِ، وَالنَّبِيَّ لَيْسَ مَعَهُ أَحَدٌ، إِذْ رُفِعَ لِي سَوَادٌ عَظِيمٌ فَظَنَنْتُ أَنَّهُمْ أُمَّتِي، فَقِيلَ لِي: هَذَا مُوسَى وَقَوْمُهُ، ثُمَّ رُفِعَ لِي سَوَادٌ عَظِيمٌ فَقِيلَ لِي: هَؤُلَاءِ أُمَّتُكَ وَمَعَهُمْ سَبْعُونَ أَلْفًا يَدْخُلُونَ الْجَنَّةَ بِغَيْرِ حِسَابٍ وَلَا عَذَابٍ»",fr:"Il m'a été montré les nations... on m'a montré une grande foule, et il m'a été dit : Ce sont les gens de Moïse. Puis on m'a montré une autre grande foule, et il m'a été dit : Ceux-ci sont ta nation, et parmi eux soixante-dix mille qui entreront au Paradis sans jugement ni châtiment.",ref:"Rapporté par al-Bukhārī (6547) et Muslim (216)"}]},
  {id:3, arNum:"الباب الثالث", arTitle:"باب الخوف من الشرك", frTitle:"La crainte du Shirk (polythéisme)", summary:"L'auteur explique que le croyant doit constamment craindre de tomber dans le shirk, même mineur. Le Prophète ﷺ a dit : « Ce que je crains le plus pour vous, c'est le shirk mineur : ar-Riyā' (l'ostentation). » Le shirk est le plus grand des péchés, et Allah ne pardonne pas qu'on Lui associe quoi que ce soit. Les prophètes eux-mêmes, malgré leur rang élevé, craignaient le shirk. Ibrahim (Abraham) ﷺ a dit : « Éloigne-moi ainsi que mes enfants du culte des idoles » (14:35). La crainte du shirk doit accompagner le croyant tout au long de sa vie, car il suffit d'un instant d'égarement pour anéantir des années d'obéissance.", verses:[{ar:"إِنَّ اللَّهَ لَا يَغْفِرُ أَنْ يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَنْ يَشَاءُ",fr:"Certes, Allah ne pardonne pas qu'on Lui associe quoi que ce soit ; et Il pardonne ce qui est moins que cela à qui Il veut.",ref:"Sourate an-Nisāʾ (4:48)"},{ar:"وَإِذْ قَالَ إِبْرَاهِيمُ رَبِّ اجْعَلْ هَٰذَا الْبَلَدَ آمِنًا وَاجْنُبْنِي وَبَنِيَّ أَن نَّعْبُدَ الْأَصْنَامَ",fr:"Et quand Abraham dit : Seigneur, fais de cette cité un lieu sûr, et éloigne-moi ainsi que mes enfants du culte des idoles.",ref:"Sourate Ibrāhīm (14:35-36)"}],hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «إِنَّ أَخْوَفَ مَا أَخَافُ عَلَيْكُمُ الشِّرْكُ الْأَصْغَرُ» قَالُوا: وَمَا الشِّرْكُ الْأَصْغَرُ يَا رَسُولَ اللَّهِ؟ قَالَ: «الرِّيَاءُ»",fr:"Ce que je crains le plus pour vous, c'est le shirk mineur. Ils dirent : Qu'est-ce que le shirk mineur, ô Messager d'Allah ? Il dit : l'ostentation.",ref:"Rapporté par Aḥmad (5/428-429)"}]},
  {id:4, arNum:"الباب الرابع", arTitle:"باب الدعاء إلى شهادة أن لا إله إلا الله", frTitle:"L'appel à l'attestation qu'il n'y a de divinité qu'Allah", summary:"Ce chapitre explique l'importance de la da'wa (l'appel) à l'attestation de foi. Le Prophète ﷺ envoya des lettres aux rois et aux dirigeants de son temps, les appelant à dire : « Il n'y a de divinité qu'Allah. » Le message du Tawḥīd est universel et doit être transmis à tous. L'auteur souligne que l'appel à l'unicité d'Allah est la mission de tous les prophètes, depuis Nūḥ (Noé) jusqu'à Muḥammad ﷺ. Chaque prophète a dit à son peuple : « Adorez Allah, vous n'avez point d'autre divinité en dehors de Lui. »", verses:[{ar:"قُلْ هَٰذِهِ سَبِيلِي أَدْعُو إِلَى اللَّهِ عَلَىٰ بَصِيرَةٍ أَنَا وَمَنِ اتَّبَعَنِي",fr:"Dis : Voici ma voie, j'appelle à Allah en toute clairvoyance, moi et ceux qui me suivent.",ref:"Sourate Yūsuf (12:108)"},{ar:"وَلَقَدْ بَعَثْنَا فِي كُلِّ أُمَّةٍ رَسُولًا أَنِ اعْبُدُوا اللَّهَ وَاجْتَنِبُوا الطَّاغُوتَ",fr:"Nous avons envoyé dans chaque communauté un Messager [pour dire] : Adorez Allah et écartez-vous du Ṭāghūt.",ref:"Sourate an-Naḥl (16:36)"}],hadiths:[{ar:"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما أَنَّ النَّبِيَّ صلى الله عليه وسلم بَعَثَ مُعَاذًا إِلَى الْيَمَنِ فَقَالَ: «إِنَّكَ تَأْتِي قَوْمًا أَهْلَ كِتَابٍ، فَلْيَكُنْ أَوَّلَ مَا تَدْعُوهُمْ إِلَيْهِ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ»",fr:"Tu vas vers un peuple du Livre. Que la première chose à laquelle tu les appelles soit l'attestation qu'il n'y a de divinité qu'Allah.",ref:"Rapporté par al-Bukhārī (1496) et Muslim (31)"}]},
  {id:5, arNum:"الباب الخامس", arTitle:"باب تفسير التوحيد وشهادة أن لا إله إلا الله", frTitle:"L'explication du Tawḥīd et de l'attestation de foi", summary:"L'auteur explique en détail le sens de l'attestation « Lā ilāha illā Allāh » : elle comporte une négation (il n'y a de divinité — nafy) et une affirmation (qu'Allah — ithbāt). Elle exige du croyant de rejeter toute fausse divinité (kufr bi al-ṭāghūt) et d'adorer Allah seul (īmān bi Allāh). L'attestation n'est pas une simple formule prononcée par la langue, mais un engagement du cœur, confirmé par la langue et concrétisé par les actes. Le shaykh commente longuement le verset du kursī comme exemple de la grandeur d'Allah qui exclut toute association.", verses:[{ar:"فَاعْلَمْ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ",fr:"Sache donc qu'il n'y a point de divinité [digne d'adoration] à part Allah.",ref:"Sourate Muḥammad (47:19)"},{ar:"لَا إِكْرَاهَ فِي الدِّينِ ۖ قَدْ تَبَيَّنَ الرُّشْدُ مِنَ الْغَيِّ ۚ فَمَنْ يَكْفُرْ بِالطَّاغُوتِ وَيُؤْمِنْ بِاللَّهِ فَقَدِ اسْتَمْسَكَ بِالْعُرْوَةِ الْوُثْقَىٰ",fr:"Nulle contrainte en religion ! Car le bon chemin s'est distingué de l'égarement. Donc, quiconque mécroit au Ṭāghūt et croit en Allah, saisit l'anse la plus solide, qui ne peut se briser.",ref:"Sourate al-Baqarah (2:256)"}],hadiths:[{ar:"عَنْ عُثْمَانَ بْنِ عَفَّانَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «مَنْ مَاتَ وَهُوَ يَعْلَمُ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ دَخَلَ الْجَنَّةَ»",fr:"Quiconque meurt en sachant qu'il n'y a de divinité qu'Allah entrera au Paradis.",ref:"Rapporté par Muslim (53)"}]},
  {id:6, arNum:"الباب السادس", arTitle:"باب من الشرك لبس الحلقة والخيط ونحوهما لدفع البلاء", frTitle:"Du shirk : le port d'anneaux, de fils et autres pour repousser le malheur", summary:"Ce chapitre traite du port d'objets tels que des anneaux, des fils, des amulettes ou des talismans dans le but de repousser le malheur ou d'attirer la bénédiction. L'auteur explique que cela constitue du shirk car le croyant place sa confiance dans ces objets plutôt qu'en Allah Seul. Le Prophète ﷺ a dit : « Quiconque porte une amulette, qu'Allah ne réalise pas son souhait ; et quiconque porte un coquillage (contre le mauvais œil), qu'Allah ne le préserve pas. » La confiance en Allah (tawakkul) doit être totale et exclusive.", verses:[{ar:"وَإِنْ يَمْسَسْكَ اللَّهُ بِضُرٍّ فَلَا كَاشِفَ لَهُ إِلَّا هُوَ ۖ وَإِنْ يُرِدْكَ بِخَيْرٍ فَلَا رَادَّ لِفَضْلِهِ",fr:"Si Allah te touche d'un mal, nul ne peut l'écarter en dehors de Lui ; et s'Il te veut un bien, nul ne peut repousser Sa faveur.",ref:"Sourate Yūnus (10:107)"}],hadiths:[{ar:"عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رضي الله عنه أَنَّ النَّبِيَّ صلى الله عليه وسلم رَأَى رَجُلًا فِي يَدِهِ حَلْقَةٌ مِنْ صُفْرٍ فَقَالَ: «مَا هَذِهِ؟» قَالَ: مِنَ الْوَاهِنَةِ. فَقَالَ: «انْزِعْهَا فَإِنَّهَا لَا تَزِيدُكَ إِلَّا وَهْنًا»",fr:"Le Prophète ﷺ vit un homme portant un anneau de laiton et lui dit : Qu'est-ce que ceci ? L'homme répondit : C'est pour la faiblesse. Le Prophète dit : Enlève-le, car cela ne fait qu'augmenter ta faiblesse.",ref:"Rapporté par Aḥmad (4/445)"},{ar:"عَنْ عُقْبَةَ بْنِ عَامِرٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «مَنْ تَعَلَّقَ تَمِيمَةً فَلَا أَتَمَّ اللَّهُ لَهُ، وَمَنْ تَعَلَّقَ وَدَعَةً فَلَا وَدَعَ اللَّهُ لَهُ»",fr:"Quiconque porte une amulette, qu'Allah n'accomplisse pas [son souhait] ; et quiconque porte un coquillage, qu'Allah ne le préserve pas.",ref:"Rapporté par Aḥmad (4/154)"}]},
  {id:7, arNum:"الباب السابع", arTitle:"باب في الرقى والتمائم", frTitle:"Les incantations (ruqā) et les amulettes (tamāʾim)", summary:"L'auteur distingue entre la ruqya légale (incantations tirées du Coran et de la Sunna) et les incantations interdites (qui impliquent des invocations à d'autres qu'Allah ou des formules incompréhensibles relevant de la sorcellerie). Les tamāʾim (amulettes) portées pour se protéger sont interdites car elles relèvent de l'association. Seule la protection d'Allah est efficace. Le grand commentateur souligne que les Compagnons considéraient toute amulette comme du shirk. La ruqya légale est permise à condition qu'elle soit en arabe, comprise, et qu'elle ne contienne rien d'incompréhensible ou d'associatif.", verses:[{ar:"وَنُنَزِّلُ مِنَ الْقُرْآنِ مَا هُوَ شِفَاءٌ وَرَحْمَةٌ لِلْمُؤْمِنِينَ",fr:"Nous faisons descendre du Coran ce qui est une guérison et une miséricorde pour les croyants.",ref:"Sourate al-Isrāʾ (17:82)"}],hadiths:[{ar:"عَنْ أَبِي بَشِيرٍ الْأَنْصَارِيِّ رضي الله عنه أَنَّهُ كَانَ مَعَ النَّبِيِّ صلى الله عليه وسلم فِي بَعْضِ أَسْفَارِهِ، فَبَعَثَ رَسُولًا: «أَنْ لَا يَبْقَيَنَّ فِي رَقَبَةِ بَعِيرٍ قِلَادَةٌ مِنْ وَتَرٍ أَوْ قِلَادَةٌ إِلَّا قُطِعَتْ»",fr:"Le Prophète ﷺ envoya un messager : Qu'il ne reste aucun collier de corde d'arc au cou d'un chameau sans qu'il soit coupé.",ref:"Rapporté par al-Bukhārī (3105) et Muslim (4291)"}]},
  {id:8, arNum:"الباب الثامن", arTitle:"باب من تبرك بشجر أو حجر أو نحو ذلك", frTitle:"Celui qui recherche la bénédiction d'un arbre, d'une pierre ou autre", summary:"L'auteur explique que la recherche de bénédiction (tabarruk) à travers des arbres, des pierres ou tout autre élément de la création est une forme de shirk. Cela rappelle la pratique des polythéistes avant l'Islam qui se rattachaient à des arbres sacrés (comme l'arbre Dhāt Anwāṭ). Le seul tabarruk légitime est celui qui est conforme à la Sunna. Le Prophète ﷺ a refusé catégoriquement à ses Compagnons, jeunes convertis, de leur désigner un arbre pour en rechercher la bénédiction, comparant leur demande à celle des fils d'Israël qui demandèrent une idole à Moïse.", verses:[{ar:"أَفَرَأَيْتُمُ اللَّاتَ وَالْعُزَّىٰ",fr:"Que vous semble d'al-Lāt et al-ʿUzzā ?",ref:"Sourate an-Najm (53:19-20)"}],hadiths:[{ar:"عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ رضي الله عنه قَالَ: خَرَجْنَا مَعَ النَّبِيِّ صلى الله عليه وسلم إِلَى حُنَيْنٍ وَنَحْنُ حُدَثَاءُ عَهْدٍ بِكُفْرٍ، وَلِلْمُشْرِكِينَ سِدْرَةٌ يَعْكُفُونَ عِنْدَهَا وَيُنَوِّطُونَ بِهَا أَسْلِحَتَهُمْ يُقَالُ لَهَا ذَاتُ أَنْوَاطٍ، فَمَرَرْنَا بِسِدْرَةٍ فَقُلْنَا: يَا رَسُولَ اللَّهِ، اجْعَلْ لَنَا ذَاتَ أَنْوَاطٍ كَمَا لَهُمْ ذَاتُ أَنْوَاطٍ. فَقَالَ النَّبِيُّ صلى الله عليه وسلم: «اللَّهُ أَكْبَرُ! إِنَّهَا السُّنَنُ، قُلْتُمْ وَالَّذِي نَفْسِي بِيَدِهِ كَمَا قَالَتْ بَنُو إِسْرَائِيلَ لِمُوسَى: اجْعَلْ لَنَا إِلَهًا كَمَا لَهُمْ آلِهَةٌ، لَتَرْكَبُنَّ سُنَنَ مَنْ كَانَ قَبْلَكُمْ»",fr:"Nous étions sortis avec le Prophète ﷺ vers Hunayn alors que nous venions tout juste de sortir de la mécréance. Les polythéistes avaient un jujubier près duquel ils se recueillaient et suspendaient leurs armes, appelé Dhāt Anwāṭ. Nous passâmes près d'un jujubier et dîmes : Ô Messager d'Allah, fais de nous un Dhāt Anwāṭ comme ils ont un Dhāt Anwāṭ ! Il répondit : Allah est Plus Grand ! Ce sont les traditions... Ce que vous dites est semblable à ce que les fils d'Israël dirent à Moïse.",ref:"Rapporté par al-Tirmidhī (2180)"}]},
  {id:9, arNum:"الباب التاسع", arTitle:"باب ما جاء في الذبح لغير الله", frTitle:"Ce qui est rapporté concernant le sacrifice pour autre qu'Allah", summary:"Le sacrifice pour autre qu'Allah est un acte majeur de shirk. L'auteur commente que celui qui immole une bête en invoquant un nom autre que celui d'Allah commet un péché gravissime. Le sacrifice est un acte d'adoration qui n'est dû qu'à Allah Seul. Le Prophète ﷺ a maudit celui qui sacrifie pour autre qu'Allah. Le shaykh Sulaymān insiste sur le fait que ce chapitre montre que le simple fait d'orienter un acte d'adoration vers autre qu'Allah — quel qu'en soit le but apparent — sort de l'Islam.", verses:[{ar:"فَصَلِّ لِرَبِّكَ وَانْحَرْ",fr:"Accomplis la Ṣalāt pour ton Seigneur et sacrifie.",ref:"Sourate al-Kawthar (108:2)"},{ar:"قُلْ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ، لَا شَرِيكَ لَهُ",fr:"Dis : En vérité, ma prière, mes actes de dévotion, ma vie et ma mort appartiennent à Allah, Seigneur de l'univers. À Lui nul associé.",ref:"Sourate al-Anʿām (6:162-163)"}],hadiths:[{ar:"عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رضي الله عنه قَالَ: حَدَّثَنِي رَسُولُ اللَّهِ صلى الله عليه وسلم: «لَعَنَ اللَّهُ مَنْ ذَبَحَ لِغَيْرِ اللَّهِ»",fr:"Qu'Allah maudisse celui qui sacrifie pour autre qu'Allah.",ref:"Rapporté par Muslim (4298)"}]},
  {id:10, arNum:"الباب العاشر", arTitle:"باب لا يذبح لله بمكان يذبح فيه لغير الله", frTitle:"On ne doit pas sacrifier pour Allah dans un lieu dédié aux sacrifices pour d'autres", summary:"Ce chapitre interdit de sacrifier pour Allah dans un endroit où des sacrifices sont également offerts à d'autres qu'Allah. Cela fait partie des moyens (sadd al-dharāʾiʿ) de protéger le Tawḥīd, car agir ainsi pourrait prêter à confusion et être une porte vers le shirk. Le Prophète ﷺ a interdit cela pour préserver la pureté du culte. L'auteur commente le hadith de l'homme qui avait fait le vœu d'égorger une chamelle à Buwāna : le Prophète ﷺ lui demanda si un temple d'idoles ou une fête païenne s'y trouvait, et ne l'autorisa qu'après confirmation qu'il n'en était rien.", hadiths:[{ar:"عَنْ ثَابِتِ بْنِ الضَّحَّاكِ رضي الله عنه قَالَ: نَذَرَ رَجُلٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صلى الله عليه وسلم أَنْ يَنْحَرَ نَاقَةً بِبُوَانَةَ، فَأَتَى النَّبِيَّ صلى الله عليه وسلم فَقَالَ: إِنِّي نَذَرْتُ أَنْ أَنْحَرَ نَاقَةً بِبُوَانَةَ. فَقَالَ النَّبِيُّ صلى الله عليه وسلم: «هَلْ كَانَ فِيهَا وَثَنٌ مِنْ أَوْثَانِ الْجَاهِلِيَّةِ يُعْبَدُ؟» قَالُوا: لَا. قَالَ: «فَهَلْ كَانَ فِيهَا عِيدٌ مِنْ أَعْيَادِهِمْ؟» قَالُوا: لَا. قَالَ: «أَوْفِ بِنَذْرِكَ فَإِنَّهُ لَا وَفَاءَ لِنَذْرٍ فِي مَعْصِيَةِ اللَّهِ»",fr:"Un homme fit le vœu d'égorger une chamelle à Buwāna. Il vint voir le Prophète ﷺ qui lui demanda : Y avait-il là une idole de la Jāhiliyya adorée ? Non. Y avait-il là une de leurs fêtes ? Non. Alors accomplis ton vœu.",ref:"Rapporté par Abū Dāwūd (3313)"}]},
  {id:11, arNum:"الباب الحادي عشر", arTitle:"باب من الشرك النذر لغير الله", frTitle:"Du shirk : le vœu (nadhr) à autre qu'Allah", summary:"Faire un vœu à autre qu'Allah est une forme de shirk, car le vœu est un acte d'adoration. L'auteur commente que le vœu (nadhr) a la même gravité que le sacrifice : c'est un engagement religieux qui ne peut être destiné qu'à Allah. Le Prophète ﷺ a dit : « Celui qui fait un vœu d'obéir à Allah, qu'il Lui obéisse ; et celui qui fait un vœu de Lui désobéir, qu'il ne Lui désobéisse pas. » Les vœux faits aux saints, aux tombes ou aux jinns sont donc du shirk majeur.", hadiths:[{ar:"عَنْ عَائِشَةَ رضي الله عنها قَالَتْ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ، وَمَنْ نَذَرَ أَنْ يَعْصِيَهُ فَلَا يَعْصِهِ»",fr:"Celui qui fait le vœu d'obéir à Allah, qu'il Lui obéisse ; et celui qui fait le vœu de Lui désobéir, qu'il ne Lui désobéisse pas.",ref:"Rapporté par al-Bukhārī (6696)"}]},
  {id:12, arNum:"الباب الثاني عشر", arTitle:"باب من الشرك الاستعاذة بغير الله", frTitle:"Du shirk : la recherche de protection auprès d'autre qu'Allah", summary:"Chercher protection (istiʿādha) auprès d'autre qu'Allah est une forme de shirk, car la protection est un attribut exclusif d'Allah. L'auteur explique que l'istiʿādha est un acte d'adoration : lorsqu'on dit « Je cherche protection auprès d'Allah » (Aʿūdhu bi-LLāh), on Lui reconnaît le pouvoir exclusif de protéger. La chercher auprès des créatures, des jinns ou des morts est donc une forme d'association. Le Prophète ﷺ enseignait à dire : « Aʿūdhu bi kalimāti llāhi al-tāmmāti min sharri mā khalaq. »", verses:[{ar:"وَأَنَّهُ كَانَ رِجَالٌ مِّنَ الْإِنسِ يَعُوذُونَ بِرِجَالٍ مِّنَ الْجِنِّ فَزَادُوهُمْ رَهَقًا",fr:"Et il y avait des humains qui cherchaient protection auprès des jinns, mais cela ne fit qu'accroître leur détresse.",ref:"Sourate al-Jinn (72:6)"}],hadiths:[{ar:"عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ رضي الله عنها قَالَتْ: سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم يَقُولُ: «مَنْ نَزَلَ مَنْزِلًا فَقَالَ: أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ، لَمْ يَضُرَّهُ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْ مَنْزِلِهِ ذَلِكَ»",fr:"Quiconque descend dans un lieu et dit : Je cherche protection par les paroles parfaites d'Allah contre le mal de ce qu'Il a créé, rien ne lui nuira jusqu'à ce qu'il quitte ce lieu.",ref:"Rapporté par Muslim (6876)"}]}
];

// ===== COMPLETE ALL 66 CHAPTERS =====
// Adding remaining chapters with standard titles
const REMAINING = [
  {id:13, arNum:"الباب الثالث عشر", arTitle:"باب من الشرك أن يستغيث بغير الله أو يدعو غيره", frTitle:"Du shirk : implorer le secours d'autre qu'Allah ou L'invoquer", summary:"Invoquer (duʿāʾ) et implorer le secours (istighātha) d'autre qu'Allah est du shirk majeur. Le duʿāʾ est le cœur de l'adoration. L'auteur commente que celui qui adresse ses invocations à un mort, un absent ou une créature pour ce qu'elle ne peut accomplir commet un shirk qui le sort de l'Islam. Le verset : « N'invoquez pas en dehors d'Allah ce qui ne peut ni vous profiter ni vous nuire » (10:106) est la règle d'or de ce chapitre.", verses:[{ar:"وَلَا تَدْعُ مِن دُونِ اللَّهِ مَا لَا يَنفَعُكَ وَلَا يَضُرُّكَ ۖ فَإِن فَعَلْتَ فَإِنَّكَ إِذًا مِّنَ الظَّالِمِينَ",fr:"N'invoque pas en dehors d'Allah ce qui ne peut ni te profiter ni te nuire ; si tu le fais, tu seras alors du nombre des injustes.",ref:"Sourate Yūnus (10:106)"},{ar:"وَقَالَ رَبُّكُمُ ادْعُونِي أَسْتَجِبْ لَكُمْ ۚ إِنَّ الَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِي سَيَدْخُلُونَ جَهَنَّمَ دَاخِرِينَ",fr:"Votre Seigneur a dit : Invoquez-Moi, Je vous exaucerai. Ceux qui, par orgueil, se dispensent de M'adorer entreront dans la Géhenne, humiliés.",ref:"Sourate Ghāfir (40:60)"}]},
  {id:14, arNum:"الباب الرابع عشر", arTitle:"باب قول الله تعالى: {أيشركون ما لا يخلق شيئا وهم يخلقون}", frTitle:"La Parole d'Allah : « Associeraient-ils ce qui ne crée rien ? »", summary:"Ce chapitre commente le verset : « Associeraient-ils (à Allah) ce qui ne crée rien, et qui sont eux-mêmes créés ? » (al-Aʿrāf 7:191). L'auteur explique l'absurdité du shirk : adorer ce qui est créé et impuissant, alors que seul le Créateur Tout-Puissant mérite l'adoration. Les idoles ne peuvent ni créer, ni subvenir aux besoins, ni repousser le mal. Comment pourraient-elles être des divinités ? Le Tawḥīd est donc la seule position rationnelle.", verses:[{ar:"أَيُشْرِكُونَ مَا لَا يَخْلُقُ شَيْئًا وَهُمْ يُخْلَقُونَ",fr:"Associeraient-ils (à Allah) ce qui ne crée rien, et qui sont eux-mêmes créés ?",ref:"Sourate al-Aʿrāf (7:191)"}]},
  {id:15, arNum:"الباب الخامس عشر", arTitle:"باب قوله تعالى: {حتى إذا فزع عن قلوبهم}", frTitle:"La Parole d'Allah : « Quand l'effroi sera ôté de leurs cœurs »", summary:"Ce chapitre commente le verset sur l'intercession des anges. Même les anges, pourtant proches d'Allah, ne peuvent intercéder qu'avec Sa permission et restent dans la crainte révérencielle. Comment alors invoquer les saints ou les prophètes en dehors d'Allah ? L'auteur développe les conditions de l'intercession légitime : (1) la permission d'Allah, (2) qu'Il soit satisfait de l'intercédé.", verses:[{ar:"حَتَّىٰ إِذَا فُزِّعَ عَن قُلُوبِهِمْ قَالُوا مَاذَا قَالَ رَبُّكُمْ ۖ قَالُوا الْحَقَّ ۖ وَهُوَ الْعَلِيُّ الْكَبِيرُ",fr:"Quand l'effroi sera ôté de leurs cœurs, ils diront : Qu'a dit votre Seigneur ? Ils répondront : La Vérité ; et c'est Lui le Très-Haut, le Très-Grand.",ref:"Sourate Sabaʾ (34:23)"}]},
  {id:16, arNum:"الباب السادس عشر", arTitle:"باب الشفاعة", frTitle:"L'intercession (ash-Shafāʿa)", summary:"Ce chapitre fondamental distingue l'intercession légalement établie (shafāʿa al-muthbata) de l'intercession polythéiste. L'intercession légitime est uniquement celle qu'Allah accorde à qui Il veut (comme le Prophète ﷺ le Jour de la Résurrection), et elle ne profite qu'à ceux qu'Allah agrée. L'intercession polythéiste est celle que les associateurs espèrent de leurs fausses divinités dans cette vie, croyant qu'elles intercéderont pour eux — c'est du shirk majeur.", verses:[{ar:"مَن ذَا الَّذِي يَشْفَعُ عِندَهُ إِلَّا بِإِذْنِهِ",fr:"Qui peut intercéder auprès de Lui sans Sa permission ?",ref:"Sourate al-Baqarah (2:255)"},{ar:"وَلَا يَشْفَعُونَ إِلَّا لِمَنِ ارْتَضَىٰ",fr:"Ils n'intercèdent qu'en faveur de ceux qu'Il agrée.",ref:"Sourate al-Anbiyāʾ (21:28)"}]},
  {id:17, arNum:"الباب السابع عشر", arTitle:"باب قوله تعالى: {قل ادعوا الذين زعمتم من دونه}", frTitle:"La Parole d'Allah : « Dis : Invoquez ceux que vous prétendez (être divinités) en dehors de Lui »", summary:"Allah ordonne à Son Prophète ﷺ de défier les associateurs : invoquez donc ceux que vous adorez en dehors d'Allah — peuvent-ils seulement guider, secourir ou créer ? La réponse est non. Ce chapitre anéantit tout argument des polythéistes qui prétendent que leurs intermédiaires leur sont utiles. L'auteur montre que ces prétendues divinités ne possèdent même pas la capacité de se guider elles-mêmes.", verses:[{ar:"قُلِ ادْعُوا الَّذِينَ زَعَمْتُم مِّن دُونِهِ فَلَا يَمْلِكُونَ كَشْفَ الضُّرِّ عَنكُمْ وَلَا تَحْوِيلًا",fr:"Dis : Invoquez ceux que vous prétendez (être des divinités) en dehors de Lui : ils ne possèdent ni le pouvoir d'écarter le mal de vous, ni de le détourner.",ref:"Sourate al-Isrāʾ (17:56)"}]},
  {id:18, arNum:"الباب الثامن عشر", arTitle:"باب أن سبب كفر بني آدم وتركهم دينهم الغلو في الصالحين", frTitle:"La cause de la mécréance des fils d'Adam et leur abandon de la religion : l'exagération dans les personnes vertueuses", summary:"L'auteur explore la genèse historique du polythéisme. Les hommes ont commencé par exagérer (ghuluww) dans l'éloge des justes, puis ont fini par les adorer. Le commentaire cite longuement l'histoire du peuple de Nūḥ (Noé) et des « cinq justes » — Wadd, Suwāʿ, Yaghūth, Yaʿūq et Nasr — qui étaient des hommes pieux, mais que leurs descendants ont fini par diviniser. C'est la première manifestation du shirk sur terre. La leçon : l'exagération dans la vénération des saints est la porte du shirk.", verses:[{ar:"وَقَالُوا لَا تَذَرُنَّ آلِهَتَكُمْ وَلَا تَذَرُنَّ وَدًّا وَلَا سُوَاعًا وَلَا يَغُوثَ وَيَعُوقَ وَنَسْرًا",fr:"Et ils dirent : N'abandonnez jamais vos divinités ; n'abandonnez ni Wadd, ni Suwāʿ, ni Yaghūth, ni Yaʿūq, ni Nasr.",ref:"Sourate Nūḥ (71:23)"}]},
  {id:19, arNum:"الباب التاسع عشر", arTitle:"باب التغليظ فيمن عبد الله عند قبر رجل صالح", frTitle:"La sévérité à l'égard de celui qui adore Allah près de la tombe d'un homme vertueux", summary:"L'auteur commente avec force que le simple fait d'adorer Allah près d'une tombe (même sans adorer le mort) est une pratique sévèrement condamnée. Le Prophète ﷺ a maudit ceux qui prennent les tombes de leurs prophètes comme lieux de prière. C'est la porte qui mène à l'adoration des tombes elles-mêmes. Les juifs et les chrétiens sont tombés dans cette erreur. C'est pourquoi la Sunna recommande d'enterrer les morts loin des lieux de prière.", hadiths:[{ar:"عَنْ عَائِشَةَ رضي الله عنها قَالَتْ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «لَعَنَ اللَّهُ الْيَهُودَ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ»",fr:"Qu'Allah maudisse les juifs et les chrétiens qui ont pris les tombes de leurs prophètes comme lieux de prière.",ref:"Rapporté par al-Bukhārī (444) et Muslim (1184)"}]},
  {id:20, arNum:"الباب العشرون", arTitle:"باب ما جاء أن الغلو في قبور الصالحين يصيرها أوثانا", frTitle:"L'exagération dans la vénération des tombes des saints les transforme en idoles", summary:"Lorsque les gens exagèrent dans la vénération des tombes des saints, ces tombes deviennent progressivement des idoles (awthān) adorées en dehors d'Allah. Le Prophète ﷺ a mis en garde contre ce phénomène historique qui s'est produit à chaque époque. Les tombes de Wadd, Suwāʿ, Yaghūth, Yaʿūq et Nasr, mentionnées dans le Coran, étaient initialement celles d'hommes pieux avant de devenir des idoles.", verses:[{ar:"وَقَالُوا لَا تَذَرُنَّ آلِهَتَكُمْ وَلَا تَذَرُنَّ وَدًّا وَلَا سُوَاعًا وَلَا يَغُوثَ وَيَعُوقَ وَنَسْرًا",fr:"N'abandonnez jamais vos divinités ; n'abandonnez ni Wadd, ni Suwāʿ, ni Yaghūth, ni Yaʿūq, ni Nasr.",ref:"Sourate Nūḥ (71:23)"}]},
  {id:21, arNum:"الباب الحادي والعشرون", arTitle:"باب حماية المصطفى جناب التوحيد", frTitle:"La protection par le Prophète ﷺ du domaine sacré du Tawḥīd", summary:"Le Prophète ﷺ a protégé le Tawḥīd en interdisant tout ce qui pourrait y conduire (sadd al-dharāʾiʿ). Il a bloqué tous les chemins menant au shirk, même ceux qui semblaient anodins. L'auteur mentionne l'interdiction du Prophète de prier au lever et au coucher du soleil, car ces moments sont ceux où les adorateurs du soleil se prosternent. Il a également interdit les voyages vers les mosquées autres que les trois mosquées sacrées.", hadiths:[{ar:"عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رضي الله عنه أَنَّ النَّبِيَّ صلى الله عليه وسلم قَالَ: «لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ: الْمَسْجِدِ الْحَرَامِ وَمَسْجِدِ الرَّسُولِ وَالْمَسْجِدِ الْأَقْصَى»",fr:"Ne voyagez [dans un but de culte] que vers trois mosquées : la Mosquée Sacrée (La Mecque), la Mosquée du Messager (Médine) et la Mosquée al-Aqṣā (Jérusalem).",ref:"Rapporté par al-Bukhārī (1264) et Muslim (2377)"}]},
  {id:22, arNum:"الباب الثاني والعشرون", arTitle:"باب ما جاء أن بعض هذه الأمة يعبد الأوثان", frTitle:"Ce qui est rapporté indiquant que certains membres de cette nation adoreront les idoles", summary:"Le Prophète ﷺ a informé sa communauté que certains parmi elle tomberont dans le shirk et adoreront des idoles. C'est une prophétie qui s'est réalisée historiquement avec l'apparition de sectes et de pratiques polythéistes au sein même de la communauté musulmane. L'auteur commente que ce hadith montre l'importance de la vigilance constante et de l'éducation au Tawḥīd. Personne n'est à l'abri si la connaissance du Tawḥīd n'est pas solidement ancrée.", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنْ النَّبِيِّ صلى الله عليه وسلم قَالَ: «لَا تَقُومُ السَّاعَةُ حَتَّى تَضْطَرِبَ آلَاتُ لَاتٍ وَعُزَّى»",fr:"L'Heure ne viendra pas avant que les fesses des femmes de Daws ne s'agitent autour de Dhū al-Khalasa (une idole).",ref:"Rapporté par Muslim (5331)"}]},
  {id:23, arNum:"الباب الثالث والعشرون", arTitle:"باب ما جاء في السحر", frTitle:"Ce qui est rapporté concernant la sorcellerie (sihr)", summary:"La sorcellerie (sihr) est une forme de mécréance et de shirk. Le Prophète ﷺ a dit : « Évitez les sept péchés destructeurs... » et a mentionné le shirk et la sorcellerie ensemble. L'auteur commente que le sorcier atteint la mécréance car il se rapproche des démons et des jinns par des actes de désobéissance et des sacrifices pour obtenir des pouvoirs surnaturels. Le sorcier doit être exécuté selon l'avis des savants — son repentir n'est pas accepté car son acte est une trahison irréversible de la religion.", verses:[{ar:"وَمَا يُعَلِّمَانِ مِنْ أَحَدٍ حَتَّىٰ يَقُولَا إِنَّمَا نَحْنُ فِتْنَةٌ فَلَا تَكْفُرْ",fr:"Ils (Hārūt et Mārūt) n'enseignaient rien à personne sans dire : Nous ne sommes qu'une tentation ; ne sois donc pas mécréant.",ref:"Sourate al-Baqarah (2:102)"}],hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ: «اجْتَنِبُوا السَّبْعَ الْمُوبِقَاتِ» قَالُوا: يَا رَسُولَ اللَّهِ، وَمَا هُنَّ؟ قَالَ: «الشِّرْكُ بِاللَّهِ، وَالسِّحْرُ...»",fr:"Évitez les sept péchés destructeurs. Ils dirent : Quels sont-ils, ô Messager d'Allah ? Il dit : Le shirk envers Allah et la sorcellerie...",ref:"Rapporté par al-Bukhārī (6857) et Muslim (177)"}]},
  {id:24, arNum:"الباب الرابع والعشرون", arTitle:"باب بيان شيء من أنواع السحر", frTitle:"L'explication de certains types de sorcellerie", summary:"L'auteur détaille les différentes formes de sorcellerie telles que les nœuds (al-ʿaqd), les souffles (al-nafth), les incantations sataniques, l'utilisation de substances impures, la manipulation d'effets personnels de la victime, et l'utilisation des noms des démons. Le Prophète ﷺ lui-même fut victime d'un acte de sorcellerie (siḥr) posé par Lubayd ibn al-Aʿṣam, mais Allah l'en protégea. L'auteur souligne que la guérison du sihr se fait par la lecture des muʿawwidhat (sourates al-Falaq et al-Nās) et des versets coraniques.", verses:[{ar:"قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ * مِن شَرِّ مَا خَلَقَ * وَمِن شَرِّ غَاسِقٍ إِذَا وَقَبَ * وَمِن شَرِّ النَّفَّاثَاتِ فِي الْعُقَدِ",fr:"Dis : Je cherche protection auprès du Seigneur de l'aube, contre le mal de ce qu'Il a créé, contre le mal de l'obscurité quand elle s'étend, contre le mal de celles qui soufflent sur les nœuds.",ref:"Sourate al-Falaq (113:1-4)"}]},
  {id:25, arNum:"الباب الخامس والعشرون", arTitle:"باب ما جاء في الكهان ونحوهم", frTitle:"Ce qui est rapporté concernant les devins (kuhhān) et autres", summary:"Consulter les devins, les diseurs de bonne aventure, les astrologues ou tout prétendant à la connaissance de l'invisible est une forme de mécréance. Le Prophète ﷺ a dit : « Celui qui va voir un devin ou un voyant et le croit en ce qu'il dit, a mécru en ce qui a été révélé à Muḥammad. » L'auteur explique que ces pratiques impliquent de croire que des créatures partagent avec Allah la connaissance de l'Invisible (ghayb), ce qui est un attribut exclusif d'Allah.", verses:[{ar:"قُل لَّا يَعْلَمُ مَن فِي السَّمَاوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ",fr:"Dis : Nul dans les cieux et sur la terre ne connaît l'Invisible, excepté Allah.",ref:"Sourate an-Naml (27:65)"}],hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ: «مَنْ أَتَى كَاهِنًا فَصَدَّقَهُ بِمَا يَقُولُ فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ»",fr:"Celui qui va voir un devin et le croit en ce qu'il dit, a mécru en ce qui a été révélé à Muḥammad.",ref:"Rapporté par Abū Dāwūd (3904)"}]},
  {id:26, arNum:"الباب السادس والعشرون", arTitle:"باب ما جاء في التنجيم", frTitle:"Ce qui est rapporté sur l'astrologie (tanjīm)", summary:"L'astrologie — la croyance que les astres influencent le destin et les événements — est une forme de shirk. L'auteur distingue entre l'astronomie utile (connaissance des saisons, des directions) et l'astrologie divinatoire (prédire l'avenir par les étoiles). Cette dernière est interdite car elle implique de croire que les astres ont un pouvoir indépendant. Le Prophète ﷺ a dit : « Quiconque apprend un chapitre de l'astrologie a appris un chapitre de la sorcellerie. »", verses:[{ar:"وَعَلَامَاتٍ ۚ وَبِالنَّجْمِ هُمْ يَهْتَدُونَ",fr:"Et des signes (pour s'orienter) ; et par les étoiles ils se guident.",ref:"Sourate an-Naḥl (16:16)"}]},
  {id:27, arNum:"الباب السابع والعشرون", arTitle:"باب ما جاء في الطيرة", frTitle:"Ce qui est rapporté sur les mauvais augures (ṭiyara)", summary:"La croyance aux mauvais augures (ṭiyara ou taṭayyur) — considérer certains animaux, moments ou événements comme de mauvais présages — est une forme de shirk mineur. Le Prophète ﷺ a dit : « La ṭiyara est du shirk » (trois fois). L'auteur commente que le remède à cette croyance est le tawakkul (la confiance en Allah). Le Prophète ﷺ enseignait à dire : « Allahumma lā khayra illā khayruka wa lā ṭayra illā ṭayruka » (Ô Allah, il n'y a de bien que Ton bien, et il n'y a d'augure que le Tien).", hadiths:[{ar:"عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «الطِّيَرَةُ مِنَ الشِّرْكِ»",fr:"Les mauvais augures relèvent du shirk.",ref:"Rapporté par Abū Dāwūd (3910) et al-Tirmidhī (1614)"}]},
  {id:28, arNum:"الباب الثامن والعشرون", arTitle:"باب ما جاء في التصوير", frTitle:"Ce qui est rapporté sur les images (taṣwīr)", summary:"La fabrication et la vénération d'images et de statues sont condamnées car elles mènent au shirk. L'auteur commente les hadiths sévères contre les fabricants d'images (musawwirūn). Le Prophète ﷺ a dit : « Les plus sévèrement châtiés le Jour de la Résurrection sont les fabricants d'images. » La raison en est que les images et statues ont toujours été le point de départ du shirk dans l'histoire humaine, comme l'illustre le récit du peuple de Nūḥ.", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «قَالَ اللَّهُ عَزَّ وَجَلَّ: وَمَنْ أَظْلَمُ مِمَّنْ ذَهَبَ يَخْلُقُ كَخَلْقِي...»",fr:"Et qui est plus injuste que celui qui entreprend de créer comme Ma création ? Qu'ils créent un atome ou un grain d'orge.",ref:"Rapporté par al-Bukhārī (5953) et Muslim (5389)"}]},
  {id:29, arNum:"الباب التاسع والعشرون", arTitle:"باب ما جاء في الاستسقاء بالأنواء", frTitle:"Ce qui est rapporté sur la demande de pluie par les positions des étoiles", summary:"Attribuer la pluie aux étoiles ou aux phénomènes célestes est une forme de shirk. Les Arabes préislamiques disaient : « Nous avons reçu la pluie grâce à telle étoile. » Le Prophète ﷺ a enseigné que le croyant doit dire : « Nous avons reçu la pluie par la grâce d'Allah et Sa miséricorde. » L'auteur commente que tout bien vient d'Allah Seul, et que les causes naturelles ne sont que des moyens qu'Il a institués.", hadiths:[{ar:"عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ رضي الله عنه قَالَ: صَلَّى بِنَا رَسُولُ اللَّهِ صلى الله عليه وسلم صَلَاةَ الصُّبْحِ بِالْحُدَيْبِيَةِ فِي إِثْرِ سَمَاءٍ كَانَتْ مِنَ اللَّيْلَةِ، فَلَمَّا انْصَرَفَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ: «هَلْ تَدْرُونَ مَاذَا قَالَ رَبُّكُمْ؟» قَالُوا: اللَّهُ وَرَسُولُهُ أَعْلَمُ. قَالَ: «قَالَ: أَصْبَحَ مِنْ عِبَادِي مُؤْمِنٌ بِي وَكَافِرٌ، فَأَمَّا مَنْ قَالَ: مُطِرْنَا بِفَضْلِ اللَّهِ وَرَحْمَتِهِ فَذَلِكَ مُؤْمِنٌ بِي كَافِرٌ بِالْكَوْكَبِ، وَأَمَّا مَنْ قَالَ: مُطِرْنَا بِنَوْءِ كَذَا وَكَذَا فَذَلِكَ كَافِرٌ بِي مُؤْمِنٌ بِالْكَوْكَبِ»",fr:"Ce matin, parmi Mes serviteurs, il y a ceux qui croient en Moi et ceux qui mécroient. Celui qui dit : Nous avons reçu la pluie par la grâce d'Allah et Sa miséricorde, celui-là croit en Moi et mécroit aux étoiles. Celui qui dit : Nous avons reçu la pluie grâce à telle étoile, celui-là mécroit en Moi et croit aux étoiles.",ref:"Rapporté par al-Bukhārī (1038) et Muslim (188)"}]},
  {id:30, arNum:"الباب الثلاثون", arTitle:"باب قوله تعالى: {ومن الناس من يتخذ من دون الله أندادا}", frTitle:"La Parole d'Allah : « Parmi les hommes, certains prennent des égaux en dehors d'Allah »", summary:"Ce chapitre traite de ceux qui prennent des « égaux » (andād) à Allah — qu'il s'agisse de personnes, d'idoles ou d'entités qu'ils aiment autant qu'ils aiment Allah. L'auteur commente que l'amour (maḥabba) est le fondement de l'adoration. Aimer quoi que ce soit d'un amour égal ou supérieur à celui dû à Allah est du shirk. Le véritable croyant aime Allah par-dessus tout, et cet amour se manifeste par l'obéissance à Ses commandements et l'évitement de Ses interdits.", verses:[{ar:"وَمِنَ النَّاسِ مَن يَتَّخِذُ مِن دُونِ اللَّهِ أَندَادًا يُحِبُّونَهُمْ كَحُبِّ اللَّهِ ۖ وَالَّذِينَ آمَنُوا أَشَدُّ حُبًّا لِّلَّهِ",fr:"Parmi les hommes, certains prennent des égaux en dehors d'Allah, les aimant comme on aime Allah. Mais ceux qui ont cru ont un amour plus intense pour Allah.",ref:"Sourate al-Baqarah (2:165)"}]},
  {id:31, arNum:"الباب الحادي والثلاثون", arTitle:"باب قوله تعالى: {قل إنما حرم ربي الفواحش}", frTitle:"La Parole d'Allah : « Dis : Mon Seigneur n'a interdit que les turpitudes »", summary:"Ce chapitre examine les interdictions divines. Allah a interdit les turpitudes (fawāḥish), qu'elles soient apparentes ou cachées, ainsi que le péché (ithm), l'agression injuste, l'association (shirk), et le fait de dire sur Allah ce qu'on ne sait pas. L'auteur commente que le shirk est la pire des turpitudes car il associe à Allah ce qu'Il n'a pas autorisé. La dissimulation des turpitudes n'en diminue pas la gravité — ce qui est caché est aussi grave que ce qui est apparent.", verses:[{ar:"قُلْ إِنَّمَا حَرَّمَ رَبِّيَ الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَالْإِثْمَ وَالْبَغْيَ بِغَيْرِ الْحَقِّ وَأَن تُشْرِكُوا بِاللَّهِ مَا لَمْ يُنَزِّلْ بِهِ سُلْطَانًا وَأَن تَقُولُوا عَلَى اللَّهِ مَا لَا تَعْلَمُونَ",fr:"Dis : Mon Seigneur n'a interdit que les turpitudes, apparentes ou cachées, le péché, l'agression injuste, d'associer à Allah ce qu'Il n'a pas autorisé, et de dire sur Allah ce que vous ne savez pas.",ref:"Sourate al-Aʿrāf (7:33)"}]},
  {id:32, arNum:"الباب الثاني والثلاثون", arTitle:"باب قوله تعالى: {وعلى الله فتوكلوا إن كنتم مؤمنين}", frTitle:"La Parole d'Allah : « Et placez votre confiance en Allah, si vous êtes croyants »", summary:"La confiance en Allah (tawakkul) est une condition de la foi. L'auteur commente que le tawakkul ne signifie pas l'abandon des moyens légitimes (asbāb), mais la confiance du cœur en Allah Seul pour les résultats. Le Prophète ﷺ lui-même portait une armure et prenait des précautions, tout en plaçant sa confiance en Allah. Le tawakkul est l'un des plus grands actes du cœur et une manifestation pure du Tawḥīd. Sans lui, la foi est incomplète.", verses:[{ar:"وَعَلَى اللَّهِ فَتَوَكَّلُوا إِن كُنتُم مُّؤْمِنِينَ",fr:"Et placez votre confiance en Allah, si vous êtes croyants.",ref:"Sourate al-Māʾidah (5:23)"},{ar:"وَمَن يَتَوَكَّلْ عَلَى اللَّهِ فَهُوَ حَسْبُهُ",fr:"Et quiconque place sa confiance en Allah, Il lui suffit.",ref:"Sourate al-Ṭalāq (65:3)"}]},
  {id:33, arNum:"الباب الثالث والثلاثون", arTitle:"باب قوله تعالى: {أفأمنوا مكر الله}", frTitle:"La Parole d'Allah : « Sont-ils à l'abri du stratagème d'Allah ? »", summary:"Se sentir à l'abri du châtiment et du stratagème d'Allah (makr Allāh) est une forme de mécréance. L'auteur commente que le croyant doit toujours craindre Allah tout en espérant Sa miséricorde. La fausse sécurité (amn) et le désespoir (yaʾs) sont deux extrêmes blâmables. Celui qui pèche en se croyant à l'abri du châtiment d'Allah ou qui désespère de Sa miséricorde commet un péché grave. Le croyant chemine entre crainte et espoir (khawf wa rajāʾ).", verses:[{ar:"أَفَأَمِنُوا مَكْرَ اللَّهِ ۚ فَلَا يَأْمَنُ مَكْرَ اللَّهِ إِلَّا الْقَوْمُ الْخَاسِرُونَ",fr:"Sont-ils à l'abri du stratagème d'Allah ? Seuls les gens perdus se croient à l'abri du stratagème d'Allah.",ref:"Sourate al-Aʿrāf (7:99)"},{ar:"إِنَّهُ لَا يَيْأَسُ مِن رَّوْحِ اللَّهِ إِلَّا الْقَوْمُ الْكَافِرُونَ",fr:"Seuls les mécréants désespèrent de la miséricorde d'Allah.",ref:"Sourate Yūsuf (12:87)"}]},
  {id:34, arNum:"الباب الرابع والثلاثون", arTitle:"باب من الإيمان بالله الصبر على أقدار الله", frTitle:"La patience face aux décrets d'Allah fait partie de la foi en Allah", summary:"La patience (ṣabr) face au décret divin (qadar) est une partie intégrante de la foi en Allah. L'auteur commente que celui qui se plaint de son destin — comme si Allah avait mal agi envers lui — ou qui maudit le temps ou les circonstances, remet en question la sagesse et la justice d'Allah. La foi au destin (al-qadāʾ wa al-qadar) est un pilier de la foi. Le croyant accepte ce qu'Allah décrète avec patience, sachant que tout vient de Lui et que Sa sagesse dépasse l'entendement humain.", verses:[{ar:"مَا أَصَابَ مِن مُّصِيبَةٍ إِلَّا بِإِذْنِ اللَّهِ ۗ وَمَن يُؤْمِن بِاللَّهِ يَهْدِ قَلْبَهُ",fr:"Nul malheur n'atteint [l'homme] qu'avec la permission d'Allah. Et quiconque croit en Allah, [Allah] guide son cœur.",ref:"Sourate al-Taghābun (64:11)"}],hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «اثْنَتَانِ فِي النَّاسِ هُمَا بِهِمْ كُفْرٌ: الطَّعْنُ فِي النَّسَبِ، وَالنِّيَاحَةُ عَلَى الْمَيِّتِ»",fr:"Deux choses chez les gens relèvent de la mécréance : médire des généalogies et se lamenter sur les morts.",ref:"Rapporté par Muslim (178)"}]},
  {id:35, arNum:"الباب الخامس والثلاثون", arTitle:"باب ما جاء في الرياء", frTitle:"Ce qui est rapporté sur l'ostentation (riyāʾ)", summary:"L'ostentation (riyāʾ) est le shirk mineur. L'auteur commente que le riyāʾ consiste à accomplir des actes d'adoration pour être vu et loué par les gens, non pour Allah. C'est un péché du cœur extrêmement dangereux car il peut anéantir les bonnes œuvres. Le Prophète ﷺ a dit : « Ce que je crains le plus pour vous, c'est le shirk mineur : le riyāʾ. » Le croyant doit purifier son intention (ikhlāṣ) pour Allah Seul dans tous ses actes.", verses:[{ar:"فَمَن كَانَ يَرْجُو لِقَاءَ رَبِّهِ فَلْيَعْمَلْ عَمَلًا صَالِحًا وَلَا يُشْرِكْ بِعِبَادَةِ رَبِّهِ أَحَدًا",fr:"Quiconque espère rencontrer son Seigneur, qu'il fasse une bonne œuvre et n'associe personne à l'adoration de son Seigneur.",ref:"Sourate al-Kahf (18:110)"}]},
  {id:36, arNum:"الباب السادس والثلاثون", arTitle:"باب من الشرك إرادة الإنسان بعمله الدنيا", frTitle:"Du shirk : vouloir par son œuvre la vie d'ici-bas", summary:"Accomplir des actes religieux dans le seul but d'obtenir des biens de ce monde (argent, statut, louange) est une forme de shirk. L'auteur commente que l'intention (niyya) détermine la validité et la récompense de l'œuvre. Si l'intention est mondaine, l'œuvre n'a aucune valeur dans l'au-delà. Allah a dit : « Quiconque désire la vie présente, Nous le rétribuerons durant celle-ci, mais ensuite il n'aura dans l'au-delà qu'un châtiment cuisant. »", verses:[{ar:"مَن كَانَ يُرِيدُ الْحَيَاةَ الدُّنْيَا وَزِينَتَهَا نُوَفِّ إِلَيْهِمْ أَعْمَالَهُمْ فِيهَا وَهُمْ فِيهَا لَا يُبْخَسُونَ * أُولَٰئِكَ الَّذِينَ لَيْسَ لَهُمْ فِي الْآخِرَةِ إِلَّا النَّارُ",fr:"Ceux qui veulent la vie présente et sa parure, Nous les rétribuerons entièrement durant celle-ci, et ils n'y seront pas lésés. Ceux-là n'auront dans l'au-delà que le Feu.",ref:"Sourate Hūd (11:15-16)"}]},
  {id:37, arNum:"الباب السابع والثلاثون", arTitle:"باب من أطاع العلماء والأمراء في تحريم ما أحل الله أو تحليل ما حرم الله", frTitle:"Celui qui obéit aux savants et aux dirigeants dans l'interdiction du licite ou l'autorisation de l'illicite", summary:"Obéir aux savants ou aux dirigeants en ce qu'ils déclarent illicite ce qu'Allah a rendu licite, ou l'inverse, est une forme de shirk. L'auteur commente que l'obéissance exclusive en matière de légalité religieuse revient à Allah et à Son Messager. Celui qui préfère la parole d'une créature au texte révélé érige cette créature en seigneur (rabb). Le verset clé est : « Ils ont pris leurs rabbins et leurs moines comme seigneurs en dehors d'Allah. »", verses:[{ar:"اتَّخَذُوا أَحْبَارَهُمْ وَرُهْبَانَهُمْ أَرْبَابًا مِّن دُونِ اللَّهِ وَالْمَسِيحَ ابْنَ مَرْيَمَ وَمَا أُمِرُوا إِلَّا لِيَعْبُدُوا إِلَٰهًا وَاحِدًا ۖ لَّا إِلَٰهَ إِلَّا هُوَ ۚ سُبْحَانَهُ عَمَّا يُشْرِكُونَ",fr:"Ils ont pris leurs rabbins et leurs moines comme seigneurs en dehors d'Allah, ainsi que le Messie, fils de Marie ; alors qu'on ne leur a ordonné que d'adorer un Dieu unique. Pas de divinité à part Lui. Gloire à Lui ! Loin de ce qu'ils Lui associent.",ref:"Sourate al-Tawbah (9:31)"}]},
  {id:38, arNum:"الباب الثامن والثلاثون", arTitle:"باب قوله تعالى: {ألم تر إلى الذين يزعمون أنهم آمنوا}", frTitle:"La Parole d'Allah : « N'as-tu pas vu ceux qui prétendent croire ? »", summary:"Ce chapitre traite de ceux qui prétendent croire au Coran mais se tournent vers le jugement des fausses autorités. L'auteur commente que l'acceptation du jugement d'Allah et du Prophète ﷺ est la condition de la foi véritable. Allah dit : « Mais non ! Par ton Seigneur ! Ils ne croiront pas jusqu'à ce qu'ils te prennent pour juge de leurs différends. » Le recours au ṭāghūt (fausse législation) pour jugement est une forme de mécréance.", verses:[{ar:"فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا فِي أَنفُسِهِمْ حَرَجًا مِّمَّا قَضَيْتَ وَيُسَلِّمُوا تَسْلِيمًا",fr:"Mais non ! Par ton Seigneur ! Ils ne croiront pas jusqu'à ce qu'ils te prennent pour juge de leurs différends, qu'ils ne ressentent alors aucune gêne de ta décision et s'y soumettent totalement.",ref:"Sourate an-Nisāʾ (4:60-65)"}]},
  {id:39, arNum:"الباب التاسع والثلاثون", arTitle:"باب من جحد شيئا من الأسماء والصفات", frTitle:"Celui qui nie quelque chose des Noms et Attributs [d'Allah]", summary:"Nier les Noms et Attributs qu'Allah s'est attribués à Lui-même, ou ceux que Son Prophète ﷺ Lui a attribués, est une forme de mécréance. L'auteur commente qu'Allah s'est décrit dans le Coran et la Sunna avec des attributs de perfection. Les affirmer sans les déformer (taḥrīf), les nier (taʿṭīl), les anthropomorphiser (tashbīh) ni s'interroger sur leur modalité (takīf) est la voie des gens de la Sunna. Le verset cité condamne ceux qui déforment les noms d'Allah.", verses:[{ar:"وَلِلَّهِ الْأَسْمَاءُ الْحُسْنَىٰ فَادْعُوهُ بِهَا ۖ وَذَرُوا الَّذِينَ يُلْحِدُونَ فِي أَسْمَائِهِ",fr:"C'est à Allah qu'appartiennent les plus beaux Noms. Invoquez-Le par ces Noms et laissez ceux qui profanent Ses Noms.",ref:"Sourate al-Aʿrāf (7:180)"}]},
  {id:40, arNum:"الباب الأربعون", arTitle:"باب قوله تعالى: {يعرفون نعمة الله ثم ينكرونها}", frTitle:"La Parole d'Allah : « Ils reconnaissent le bienfait d'Allah puis le renient »", summary:"Le déni des bienfaits d'Allah est une forme de mécréance. Les associateurs reconnaissaient qu'Allah est le Créateur et le Pourvoyeur, mais ils Lui associaient d'autres dans l'adoration. Leur shirk résidait dans le culte, non dans la reconnaissance de la Seigneurie (rubūbiyya). L'auteur commente que le déni du bienfait peut être : (1) le nier totalement en l'attribuant à autre qu'Allah, ou (2) l'attribuer à sa propre intelligence ou à ses efforts, oubliant que c'est Allah qui en est la Source.", verses:[{ar:"يَعْرِفُونَ نِعْمَتَ اللَّهِ ثُمَّ يُنكِرُونَهَا وَأَكْثَرُهُمُ الْكَافِرُونَ",fr:"Ils reconnaissent le bienfait d'Allah puis le renient ; la plupart d'entre eux sont des mécréants.",ref:"Sourate an-Naḥl (16:83)"}]},
  {id:41, arNum:"الباب الحادي والأربعون", arTitle:"باب قوله تعالى: {فلا تجعلوا لله أندادا وأنتم تعلمون}", frTitle:"La Parole d'Allah : « Ne donnez donc pas d'égaux à Allah alors que vous savez »", summary:"Allah interdit de Lui donner des égaux (andād). L'auteur commente que l'association peut être évidente (shirk jaliy) ou subtile (shirk khafiy). Le verset dit « alors que vous savez » — car la preuve de l'unicité d'Allah est claire dans la création et la révélation. Le polythéiste n'a aucune excuse. Le Tawḥīd est la seule religion conforme à la raison et à la nature primitive (fiṭra) sur laquelle Allah a créé l'homme.", verses:[{ar:"فَلَا تَجْعَلُوا لِلَّهِ أَندَادًا وَأَنتُمْ تَعْلَمُونَ",fr:"Ne donnez donc pas d'égaux à Allah alors que vous savez [qu'Il est votre Créateur].",ref:"Sourate al-Baqarah (2:22)"}]},
  {id:42, arNum:"الباب الثاني والأربعون", arTitle:"باب من لم يقنع بالحلف بالله", frTitle:"Celui qui n'est pas satisfait du serment par Allah", summary:"Exiger un serment par autre qu'Allah ou ne pas se satisfaire d'un serment par Allah seul est une forme de shirk. L'auteur commente que si l'on ne se contente pas de « par Allah » et qu'on exige un serment par un ancêtre, un saint ou une autre créature, cela indique une faiblesse dans le Tawḥīd. Le Prophète ﷺ a dit : « Quiconque jure par autre qu'Allah a commis un acte de shirk. » Le serment n'est légitime que par Allah, par Ses Noms ou par Ses Attributs.", hadiths:[{ar:"عَنْ عُمَرَ بْنِ الْخَطَّابِ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «مَنْ حَلَفَ بِغَيْرِ اللَّهِ فَقَدْ كَفَرَ أَوْ أَشْرَكَ»",fr:"Quiconque jure par autre qu'Allah a commis un acte de mécréance ou d'association.",ref:"Rapporté par al-Tirmidhī (1535)"}]},
  {id:43, arNum:"الباب الثالث والأربعون", arTitle:"باب قول: ما شاء الله وشئت", frTitle:"Les paroles : « Ce qu'Allah veut et ce que tu veux »", summary:"Dire « Ce qu'Allah veut et ce que tu veux » (mā shāʾa Allāh wa shiʾta) est interdit car cela associe la volonté humaine à celle d'Allah sur un pied d'égalité. L'auteur commente le récit où un homme dit au Prophète ﷺ : « Ce qu'Allah veut et ce que tu veux. » Le Prophète ﷺ corrigea : « M'as-tu placé comme égal à Allah ? Dis plutôt : Ce qu'Allah veut seul. » La volonté d'Allah est absolue et indépendante ; la volonté humaine Lui est soumise.", hadiths:[{ar:"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما أَنَّ رَجُلًا قَالَ لِلنَّبِيِّ صلى الله عليه وسلم: مَا شَاءَ اللَّهُ وَشِئْتَ. فَقَالَ: «أَجَعَلْتَنِي لِلَّهِ نِدًّا؟ بَلْ مَا شَاءَ اللَّهُ وَحْدَهُ»",fr:"Un homme dit au Prophète ﷺ : Ce qu'Allah veut et ce que tu veux. Il dit : M'as-tu placé comme égal à Allah ? Dis plutôt : Ce qu'Allah veut seul.",ref:"Rapporté par Aḥmad (1/283)"}]},
  {id:44, arNum:"الباب الرابع والأربعون", arTitle:"باب من سب الدهر فقد آذى الله", frTitle:"Celui qui insulte le temps a offensé Allah", summary:"Insulter le temps (dahr) est interdit car le temps est une créature d'Allah à travers laquelle Il fait se succéder les événements. Quand quelqu'un maudit le temps pour les malheurs qui l'atteignent, c'est en réalité Allah qu'il offense, car c'est Allah qui a décrété ces événements. Le Prophète ﷺ rapporte qu'Allah dit : « Le fils d'Adam M'offense en insultant le temps, alors que Je suis le Temps (ad-Dahr). » Cela signifie qu'Allah est le Maître du temps et de tout ce qui s'y produit.", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «قَالَ اللَّهُ عَزَّ وَجَلَّ: يُؤْذِينِي ابْنُ آدَمَ يَسُبُّ الدَّهْرَ، وَأَنَا الدَّهْرُ، بِيَدِي الْأَمْرُ، أُقَلِّبُ اللَّيْلَ وَالنَّهَارَ»",fr:"Le fils d'Adam M'offense en insultant le temps, alors que Je suis le Temps (ad-Dahr) : c'est Moi qui dispose de tout, J'alterne la nuit et le jour.",ref:"Rapporté par al-Bukhārī (6181) et Muslim (979)"}]},
  {id:45, arNum:"الباب الخامس والأربعون", arTitle:"باب التسمي بقاضي القضاة ونحوه", frTitle:"Se faire appeler 'Juge des juges' ou titre similaire", summary:"Il est interdit de s'attribuer des titres qui ne conviennent qu'à Allah, comme « Roi des rois », « Juge des juges », ou « Maître des maîtres ». Le Prophète ﷺ a dit : « Le nom le plus détestable pour Allah le Jour de la Résurrection sera un homme qui se fait appeler : Roi des rois. » L'auteur commente que ces titres impliquent une souveraineté absolue qui n'appartient qu'à Allah. Le croyant doit s'humilier et ne pas revendiquer ce qui est exclusif à Allah.", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ: «إِنَّ أَخْنَعَ اسْمٍ عِنْدَ اللَّهِ رَجُلٌ تَسَمَّى بِمَلِكِ الْأَمْلَاكِ»",fr:"Le nom le plus vil auprès d'Allah est celui d'un homme qui s'appelle 'Roi des rois'.",ref:"Rapporté par al-Bukhārī (6205) et Muslim (5232)"}]},
  {id:46, arNum:"الباب السادس والأربعون", arTitle:"باب احترام أسماء الله وتغيير الاسم لأجل ذلك", frTitle:"Le respect des Noms d'Allah et le changement de nom pour cela", summary:"Il faut respecter les Noms d'Allah et ne pas les utiliser de manière irrévérencieuse. Si un nom peut prêter à confusion ou manquer de respect envers Allah, il faut le changer. L'auteur rapporte que le Prophète ﷺ changeait les noms qui impliquaient une association ou une mauvaise signification. Par exemple, il changea le nom d'une femme appelée ʿĀṣiya (désobéissante) en Jamīla (belle). Le respect des Noms d'Allah est une manifestation du Tawḥīd.", hadiths:[{ar:"عَنْ أَبِي شُرَيْحٍ رضي الله عنه أَنَّهُ كَانَ يُكَنَّى أَبَا الْحَكَمِ فَقَالَ لَهُ النَّبِيُّ صلى الله عليه وسلم: «إِنَّ اللَّهَ هُوَ الْحَكَمُ وَإِلَيْهِ الْحُكْمُ» فَقَالَ: إِنَّ قَوْمِي إِذَا اخْتَلَفُوا فِي شَيْءٍ أَتُونِي فَحَكَمْتُ بَيْنَهُمْ فَرَضِيَ كِلَا الْفَرِيقَيْنِ. فَقَالَ: «مَا أَحْسَنَ هَذَا! فَمَا لَكَ مِنَ الْوَلَدِ؟» قَالَ: شُرَيْحٌ وَمُسْلِمٌ وَعَبْدُ اللَّهِ. قَالَ: «فَمَنْ أَكْبَرُهُمْ؟» قُلْتُ: شُرَيْحٌ. قَالَ: «فَأَنْتَ أَبُو شُرَيْحٍ»",fr:"Le Prophète ﷺ dit à Abū al-Ḥakam : Allah est le Juge (al-Ḥakam) et le jugement Lui appartient. Change ton surnom.",ref:"Rapporté par Abū Dāwūd (4955) et al-Nasāʾī"}]},
  {id:47, arNum:"الباب السابع والأربعون", arTitle:"باب من هزل بشيء فيه ذكر الله أو القرآن أو الرسول", frTitle:"Celui qui plaisante à propos de ce qui mentionne Allah, le Coran ou le Prophète", summary:"Se moquer ou plaisanter de la religion, du Coran, du Prophète ﷺ ou de tout ce qui concerne Allah est un acte de mécréance. L'auteur commente le verset où les hypocrites disent en plaisantant des paroles moqueuses sur la religion, et Allah révèle : « Dis : Est-ce d'Allah, de Ses versets et de Son Messager que vous vous moquiez ? Ne vous excusez pas : vous avez bel et bien mécru après avoir cru. » La plaisanterie n'excuse pas la mécréance — qu'elle soit dite sérieusement ou par dérision.", verses:[{ar:"وَلَئِن سَأَلْتَهُمْ لَيَقُولُنَّ إِنَّمَا كُنَّا نَخُوضُ وَنَلْعَبُ ۚ قُلْ أَبِاللَّهِ وَآيَاتِهِ وَرَسُولِهِ كُنتُمْ تَسْتَهْزِئُونَ * لَا تَعْتَذِرُوا قَدْ كَفَرْتُم بَعْدَ إِيمَانِكُمْ",fr:"Et si tu les interrogeais, ils diraient : Nous ne faisions que parler et jouer. Dis : Est-ce d'Allah, de Ses versets et de Son Messager que vous vous moquiez ? Ne vous excusez pas : vous avez bel et bien mécru après avoir cru.",ref:"Sourate al-Tawbah (9:65-66)"}]},
  {id:48, arNum:"الباب الثامن والأربعون", arTitle:"باب قوله تعالى: {ولئن أذقنا الإنسان منا رحمة}", frTitle:"La Parole d'Allah : « Si Nous faisons goûter à l'homme une miséricorde de Notre part »", summary:"Ce chapitre traite de l'ingratitude humaine. Quand Allah accorde un bienfait, l'homme s'en réjouit et est reconnaissant ; mais quand un malheur le frappe après le bienfait, il désespère et renie les faveurs passées. L'auteur commente que l'attitude du croyant doit être constante : reconnaître le bienfait dans l'aisance et la patience dans l'épreuve, sans jamais renier la grâce d'Allah.", verses:[{ar:"وَلَئِنْ أَذَقْنَا الْإِنسَانَ مِنَّا رَحْمَةً ثُمَّ نَزَعْنَاهَا مِنْهُ إِنَّهُ لَيَئُوسٌ كَفُورٌ",fr:"Si Nous faisons goûter à l'homme une miséricorde de Notre part, puis la lui retirons, le voilà désespéré et ingrat.",ref:"Sourate Hūd (11:9)"}]},
  {id:49, arNum:"الباب التاسع والأربعون", arTitle:"باب قوله تعالى: {فلما آتاهما صالحا جعلا له شركاء}", frTitle:"La Parole d'Allah : « Quand Il leur eut donné un enfant vertueux, ils Lui attribuèrent des associés »", summary:"Ce chapitre traite du shirk dans la gratitude envers Allah pour la naissance d'un enfant. L'auteur commente le verset qui évoque Adam et Hawwāʾ (Ève) : quand Allah leur donna un enfant sain, Satan les tenta en leur suggérant de nommer l'enfant « ʿAbd al-Ḥārith » (serviteur du laboureur) par reconnaissance envers autre qu'Allah. L'auteur mentionne que certains exégètes voient dans ce verset une allusion à la tendance humaine d'associer dans la joie et la gratitude.", verses:[{ar:"فَلَمَّا آتَاهُمَا صَالِحًا جَعَلَا لَهُ شُرَكَاءَ فِيمَا آتَاهُمَا ۚ فَتَعَالَى اللَّهُ عَمَّا يُشْرِكُونَ",fr:"Quand Il leur eut donné un enfant vertueux, ils Lui attribuèrent des associés dans ce qu'Il leur avait donné. Allah est bien au-dessus de ce qu'ils Lui associent.",ref:"Sourate al-Aʿrāf (7:190)"}]},
  {id:50, arNum:"الباب الخمسون", arTitle:"باب قوله تعالى: {ويجعلون لله ما يكرهون}", frTitle:"La Parole d'Allah : « Ils attribuent à Allah ce qu'ils détestent »", summary:"Les polythéistes attribuent à Allah ce qu'ils détestent pour eux-mêmes — des filles par exemple — tandis qu'ils s'attribuent ce qu'ils préfèrent. L'auteur commente l'absurdité de la croyance des Arabes préislamiques qui considéraient les anges comme des filles d'Allah tout en dédaignant les filles pour eux-mêmes. Ce chapitre montre l'incohérence et l'injustice du shirk : on attribue à Allah ce qu'on méprise pour soi.", verses:[{ar:"وَيَجْعَلُونَ لِلَّهِ مَا يَكْرَهُونَ وَتَصِفُ أَلْسِنَتُهُمُ الْكَذِبَ أَنَّ لَهُمُ الْحُسْنَىٰ ۖ لَا جَرَمَ أَنَّ لَهُمُ النَّارَ وَأَنَّهُم مُّفْرَطُونَ",fr:"Ils attribuent à Allah ce qu'ils détestent [pour eux-mêmes] ; leurs langues profèrent le mensonge : ce qu'il y a de meilleur leur est réservé. En vérité, le Feu leur est destiné.",ref:"Sourate an-Naḥl (16:62)"}]},
  {id:51, arNum:"الباب الحادي والخمسون", arTitle:"باب أنه لا يقال: السلام على الله", frTitle:"Il ne faut pas dire : « Que la paix soit sur Allah »", summary:"Il est interdit de dire « al-Salāmu ʿalā Allāh » (Que la paix soit sur Allah) car Allah est la source même de la paix (al-Salām). C'est Lui qui accorde la paix à Ses créatures, non l'inverse. Le Prophète ﷺ a enseigné aux Compagnons de dire dans leurs prières : « al-Taḥiyyātu li-LLāh... » (les salutations à Allah), non « al-Salāmu ʿalā Allāh ». L'auteur commente que cela préserve les Noms et Attributs d'Allah de toute imperfection.", hadiths:[{ar:"عَنِ ابْنِ مَسْعُودٍ رضي الله عنه قَالَ: كُنَّا إذَا قَعَدْنَا مَعَ النَّبِيِّ صلى الله عليه وسلم فِي الصَّلَاةِ قُلْنَا: السَّلَامُ عَلَى اللَّهِ مِنْ عِبَادِهِ، السَّلَامُ عَلَى فُلَانٍ وَفُلَانٍ. فَقَالَ النَّبِيُّ صلى الله عليه وسلم: «لَا تَقُولُوا: السَّلَامُ عَلَى اللَّهِ فَإِنَّ اللَّهَ هُوَ السَّلَامُ»",fr:"Ne dites pas : 'Que la paix soit sur Allah', car Allah est la Paix (al-Salām) Lui-même.",ref:"Rapporté par al-Bukhārī (831) et Muslim (2005)"}]},
  {id:52, arNum:"الباب الثاني والخمسون", arTitle:"باب قول: اللهم اغفر لي إن شئت", frTitle:"Dire : « Ô Allah, pardonne-moi si Tu veux »", summary:"Il est interdit de conditionner ses invocations en disant « Ô Allah, pardonne-moi si Tu veux. » Le Prophète ﷺ a dit : « Que l'un de vous ne dise pas : Ô Allah, pardonne-moi si Tu veux ; mais qu'il soit résolu dans sa demande. » L'auteur commente que cette restriction implique un manque de conviction en la puissance et la générosité d'Allah. Le croyant doit demander avec détermination (ʿazm) et confiance, car rien n'est trop grand pour Allah.", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «لَا يَقُولَنَّ أَحَدُكُمُ: اللَّهُمَّ اغْفِرْ لِي إِنْ شِئْتَ، اللَّهُمَّ ارْحَمْنِي إِنْ شِئْتَ، لِيَعْزِمِ الْمَسْأَلَةَ، فَإِنَّ اللَّهَ لَا مُكْرِهَ لَهُ»",fr:"Que l'un de vous ne dise pas : Ô Allah, pardonne-moi si Tu veux ; mais qu'il soit résolu dans sa demande, car nul ne peut contraindre Allah.",ref:"Rapporté par al-Bukhārī (6339) et Muslim (4898)"}]},
  {id:53, arNum:"الباب الثالث والخمسون", arTitle:"باب لا يقول: عبدي وأمتي", frTitle:"Ne pas dire : « Mon serviteur » ou « Ma servante »", summary:"Il est préférable de ne pas dire « ʿabdī » (mon serviteur) ou « amatī » (ma servante) car ces termes ne conviennent parfaitement qu'à Allah — tous les humains sont les serviteurs d'Allah. Le Prophète ﷺ a enseigné de dire plutôt « fatāya » (mon jeune homme) ou « fatātī » (ma jeune fille). L'auteur commente que cela relève du respect des termes qui appartiennent exclusivement à Allah dans leur sens absolu.", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «لَا يَقُولَنَّ أَحَدُكُمْ: أَطْعِمْ رَبَّكَ، وَضِّئْ رَبَّكَ، وَلْيَقُلْ: سَيِّدِي وَمَوْلَايَ. وَلَا يَقُولَنَّ أَحَدُكُمْ: عَبْدِي وَأَمَتِي، وَلْيَقُلْ: فَتَايَ وَفَتَاتِي وَغُلَامِي»",fr:"Que l'un de vous ne dise pas : 'Mon serviteur' ou 'Ma servante', mais qu'il dise : 'Mon jeune homme' ou 'Ma jeune fille'.",ref:"Rapporté par Muslim (5313)"}]},
  {id:54, arNum:"الباب الرابع والخمسون", arTitle:"باب لا يرد من سأل بالله", frTitle:"On ne doit pas repousser celui qui demande par Allah", summary:"Refuser la demande de quelqu'un qui implore par Allah est sévèrement condamné. Le Prophète ﷺ a dit : « Celui qui demande par Allah, donnez-lui. » L'auteur commente que ne pas répondre à celui qui invoque le Nom d'Allah est un mépris de la sacralité du Nom divin. Cela ne signifie pas qu'il faille donner tout ce qui est demandé sans discernement, mais qu'il faut répondre avec bienveillance et générosité dans la mesure du possible.", hadiths:[{ar:"عَنِ ابْنِ عُمَرَ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «مَنْ سَأَلَ بِاللَّهِ فَأَعْطُوهُ، وَمَنِ اسْتَعَاذَ بِاللَّهِ فَأَعِيذُوهُ، وَمَنْ دَعَاكُمْ فَأَجِيبُوهُ، وَمَنْ صَنَعَ إِلَيْكُمْ مَعْرُوفًا فَكَافِئُوهُ»",fr:"Celui qui demande par Allah, donnez-lui ; celui qui cherche protection par Allah, protégez-le ; celui qui vous invite, répondez-lui ; et celui qui vous fait une faveur, récompensez-le.",ref:"Rapporté par Abū Dāwūd (1672) et al-Nasāʾī"}]},
  {id:55, arNum:"الباب الخامس والخمسون", arTitle:"باب ما جاء في: لا وأبيك ونحوه", frTitle:"Ce qui est rapporté concernant les paroles : 'Non, par ton père' et autres", summary:"Jurer par ses ancêtres, par son père ou par toute autre créature est interdit. Le Prophète ﷺ a dit : « Nul ne jure par vos pères ; que celui qui veut jurer jure par Allah ou qu'il se taise. » L'auteur commente que l'interdiction inclut tous les serments par les créatures, même les choses sacrées comme la Kaʿba ou le Prophète ﷺ. Seul le serment par Allah, par Ses Noms ou par Ses Attributs est légitime.", hadiths:[{ar:"عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «أَلَا إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ، فَمَنْ كَانَ حَالِفًا فَلْيَحْلِفْ بِاللَّهِ أَوْ لِيَصْمُتْ»",fr:"Certes, Allah vous interdit de jurer par vos pères. Que celui qui veut jurer jure par Allah ou qu'il se taise.",ref:"Rapporté par al-Bukhārī (2679) et Muslim (4562)"}]},
  {id:56, arNum:"الباب السادس والخمسون", arTitle:"باب ما جاء في: لو", frTitle:"Ce qui est rapporté concernant le mot 'Si' (law)", summary:"L'usage du mot « law » (si) pour exprimer le regret face au destin est répréhensible. Le Prophète ﷺ a dit : « Si le malheur te frappe, ne dis pas : Si j'avais fait ceci, cela serait arrivé autrement ; mais dis : Allah a décrété et ce qu'Il a voulu est arrivé. » L'auteur commente que « law » ouvre la porte à Satan et exprime une insatisfaction face au décret divin. Le croyant doit accepter le qaḍāʾ et le qadar.", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «الْمُؤْمِنُ الْقَوِيُّ خَيْرٌ وَأَحَبُّ إِلَى اللَّهِ مِنَ الْمُؤْمِنِ الضَّعِيفِ، وَفِي كُلٍّ خَيْرٌ. احْرِصْ عَلَى مَا يَنْفَعُكَ، وَاسْتَعِنْ بِاللَّهِ وَلَا تَعْجَزْ. وَإِنْ أَصَابَكَ شَيْءٌ فَلَا تَقُلْ: لَوْ أَنِّي فَعَلْتُ كَانَ كَذَا وَكَذَا، وَلَكِنْ قُلْ: قَدَّرَ اللَّهُ وَمَا شَاءَ فَعَلَ، فَإِنَّ لَوْ تَفْتَحُ عَمَلَ الشَّيْطَانِ»",fr:"...Si le malheur te frappe, ne dis pas : Si j'avais fait, cela serait arrivé ; mais dis : Allah a décrété et ce qu'Il a voulu est arrivé, car 'si' ouvre l'œuvre de Satan.",ref:"Rapporté par Muslim (6703)"}]},
  {id:57, arNum:"الباب السابع والخمسون", arTitle:"باب النهي عن سب الريح", frTitle:"L'interdiction d'insulter le vent", summary:"Insulter le vent (ou tout phénomène naturel) est interdit car le vent est une créature d'Allah soumise à Son ordre. Le Prophète ﷺ a dit : « N'insultez pas le vent. » L'auteur commente que lorsque les gens insultent le vent pour les dégâts qu'il cause, c'est en réalité Allah qu'ils blâment. Le croyant doit plutôt dire : « Ô Allah, fais-nous en profiter et ne nous en fais pas de mal. »", hadiths:[{ar:"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «الرِّيْحُ مِنْ رَوْحِ اللَّهِ تَأْتِي بِالرَّحْمَةِ وَبِالْعَذَابِ، فَلَا تَسُبُّوهَا، وَسَلُوا اللَّهَ مِنْ خَيْرِهَا، وَعُوذُوا بِاللَّهِ مِنْ شَرِّهَا»",fr:"Le vent provient de la miséricorde d'Allah, il apporte la miséricorde ou le châtiment ; ne l'insultez pas, demandez à Allah d'en obtenir le bien et cherchez refuge auprès d'Allah contre son mal.",ref:"Rapporté par Abū Dāwūd (5097) et al-Tirmidhī (2252)"}]},
  {id:58, arNum:"الباب الثامن والخمسون", arTitle:"باب قوله تعالى: {ويظنون أنهم على شيء}", frTitle:"La Parole d'Allah : « Ils pensent être sur quelque chose »", summary:"Ce chapitre commente le verset sur les hypocrites qui s'imaginent être sur la bonne voie alors qu'ils sont dans l'égarement. L'auteur commente que l'auto-illusion est l'un des plus grands dangers pour le croyant. On peut accomplir des actes qui semblent bons mais qui sont viciés par l'intention ou l'innovation. Le croyant doit constamment examiner sa foi et ses actes à la lumière du Coran et de la Sunna.", verses:[{ar:"وَيَظُنُّونَ أَنَّهُمْ عَلَىٰ شَيْءٍ ۖ أَلَا إِنَّهُمْ هُمُ الْكَاذِبُونَ",fr:"Ils pensent être sur quelque chose [de vrai]... En vérité, ce sont eux les menteurs.",ref:"Sourate al-Mujādilah (58:18)"}]},
  {id:59, arNum:"الباب التاسع والخمسون", arTitle:"باب ما جاء في منكري القدر", frTitle:"Ce qui est rapporté sur les négateurs du Décret divin (Qadar)", summary:"Ce chapitre traite de ceux qui nient le décret divin (qadar). Le Prophète ﷺ a dit : « Si l'on parle des négateurs du qadar, éloignez-vous d'eux. » L'auteur commente que la croyance au qadar — le bien comme le mal vient d'Allah — est un pilier de la foi. Ceux qui nient que toute chose est décrétée par Allah tombent dans une forme d'association en attribuant l'existence du mal à autre qu'Allah. La voie des gens de la Sunna est d'affirmer que le qadar est le secret d'Allah dans Sa création.", hadiths:[{ar:"عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «الْقَدَرِيَّةُ مَجُوسُ هَذِهِ الْأُمَّةِ»",fr:"Les Qadariyya (négateurs du décret) sont les mages de cette nation.",ref:"Rapporté par Abū Dāwūd (4691)"}]},
  {id:60, arNum:"الباب الستون", arTitle:"باب ما جاء في المصورين", frTitle:"Ce qui est rapporté sur les fabricateurs d'images", summary:"La fabrication d'images et de statues d'êtres animés est sévèrement interdite. Le Prophète ﷺ a dit : « Les plus sévèrement châtiés le Jour de la Résurrection sont les fabricants d'images. » L'auteur commente que cette interdiction est liée à la protection du Tawḥīd, car les images ont toujours été le vecteur du shirk idolâtre. Les savants distinguent entre les images ayant une ombre (statues) — interdites sans exception — et les images plates pour une nécessité (photos d'identité, etc.) selon certains avis contemporains.", hadiths:[{ar:"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم يَقُولُ: «كُلُّ مُصَوِّرٍ فِي النَّارِ، يُجْعَلُ لَهُ بِكُلِّ صُورَةٍ صَوَّرَهَا نَفْسٌ فَيُعَذَّبُ بِهَا فِي جَهَنَّمَ»",fr:"Tout fabricant d'images est en Enfer ; il lui sera attribué pour chaque image qu'il a fabriquée une âme qui le châtiera en Enfer.",ref:"Rapporté par al-Bukhārī (5963) et Muslim (5313)"}]},
  {id:61, arNum:"الباب الحادي والستون", arTitle:"باب ما جاء في كثرة الحلف", frTitle:"Ce qui est rapporté sur les nombreux serments", summary:"Jurer fréquemment par Allah est répréhensible car cela banalise le Nom d'Allah. Allah dit : « Et gardez vos serments. » Le Prophète ﷺ a dit : « Ne jurez ni par vos pères, ni par vos mères, ni par les idoles ; ne jurez que par Allah et ne jurez que lorsque vous êtes véridiques. » L'auteur commente que le serment excessif indique un manque de respect pour le Nom d'Allah et peut mener au parjure. Le croyant ne doit jurer que rarement et seulement par Allah, en étant véridique.", verses:[{ar:"وَاحْفَظُوا أَيْمَانَكُمْ",fr:"Et gardez vos serments.",ref:"Sourate al-Māʾidah (5:89)"}]},
  {id:62, arNum:"الباب الثاني والستون", arTitle:"باب ما جاء في ذمة الله وذمة نبيه", frTitle:"Ce qui est rapporté sur la protection d'Allah et la protection de Son Prophète", summary:"Il est interdit de trahir la protection (dhimma) accordée par Allah ou par Son Prophète ﷺ. L'auteur commente que les pactes et les engagements pris au nom d'Allah ou de Son Messager sont sacrés et doivent être honorés. Le Prophète ﷺ a dit : « Les musulmans sont tenus par leur pacte. » Trahir un engagement pris au nom de la religion est une forme de manquement au Tawḥīd, car cela implique un manque de crainte d'Allah.", hadiths:[{ar:"عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رضي الله عنهما قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «الْمُسْلِمُونَ تَتَكَافَأُ دِمَاؤُهُمْ، وَيَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ، وَهُمْ يَدٌ عَلَى مَنْ سِوَاهُمْ»",fr:"Les musulmans sont égaux en ce qui concerne le sang ; le plus humble d'entre eux peut accorder une protection qui engage tous les autres.",ref:"Rapporté par Abū Dāwūd (4531)"}]},
  {id:63, arNum:"الباب الثالث والستون", arTitle:"باب ما جاء في الإقسام على الله", frTitle:"Ce qui est rapporté concernant l'exigence d'un serment envers Allah", summary:"Demander à Allah avec insistance en Lui faisant jurer par Sa gloire ou Sa puissance est permis si c'est fait avec révérence, mais exiger quelque chose d'Allah comme si on avait des droits sur Lui est répréhensible. L'auteur commente les hadiths où les Compagnons et les pieux prédécesseurs imploraient Allah en Lui demandant par Sa puissance et Sa miséricorde, ce qui montre leur confiance absolue en Sa générosité. Le Prophète ﷺ a dit : « Il est des serviteurs d'Allah qui, s'ils jurent par Allah, Allah réalise leur serment. »", hadiths:[{ar:"عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ»",fr:"Il est des serviteurs d'Allah qui, s'ils jurent par Allah, Allah réalise leur serment.",ref:"Rapporté par al-Bukhārī (7465)"}]},
  {id:64, arNum:"الباب الرابع والستون", arTitle:"باب لا يستشفع بالله على خلقه", frTitle:"On ne doit pas chercher l'intercession d'Allah auprès de Sa création", summary:"Chercher l'intercession d'Allah auprès de Sa création — dire par exemple « Qu'Allah intercède pour moi auprès d'Untel » — est interdit car cela inverse la relation de l'intercession : c'est Allah que l'on implore pour les créatures, non l'inverse. L'auteur commente que ce chapitre préserve la majesté d'Allah. Les créatures implorent Allah, non l'inverse. Le hadith d'al-Ṭabarānī montre que le Prophète ﷺ a enseigné de dire : « Ô Allah, je Te demande pour mon bien », non « Je Te prends pour intercesseur. »", hadiths:[{ar:"عَنْ جُبَيْرِ بْنِ مُطْعِمٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «يَا بَنِي عَبْدِ مَنَافٍ، لَا تَمْنَعُوا أَحَدًا طَافَ بِهَذَا الْبَيْتِ وَصَلَّى أَيَّ سَاعَةٍ شَاءَ مِنْ لَيْلٍ أَوْ نَهَارٍ»",fr:"Ô Banū ʿAbd Manāf, n'empêchez personne de faire le tour de cette Maison et de prier à toute heure de jour ou de nuit.",ref:"Rapporté par al-Tirmidhī (868)"}]},
  {id:65, arNum:"الباب الخامس والستون", arTitle:"باب ما جاء في حماية المصطفى حمى التوحيد", frTitle:"Ce qui est rapporté sur la protection par le Prophète du sanctuaire du Tawḥīd", summary:"Le Prophète ﷺ a protégé le Tawḥīd en rendant illicite tout ce qui pourrait y conduire. Il a interdit les prières surérogatoires après la prière de l'aube jusqu'au lever du soleil, et après la prière de l'après-midi jusqu'au coucher du soleil, parce que ces périodes sont celles où les adorateurs du soleil se prosternent. Ce chapitre montre que les actions apparemment anodines peuvent être des portes vers le shirk, et que le Prophète ﷺ, dans sa miséricorde pour sa communauté, a bloqué ces portes.", hadiths:[{ar:"عَنِ ابْنِ عُمَرَ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم: «إِذَا طَلَعَ حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تَرْتَفِعَ، وَإِذَا غَابَ حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تَغِيبَ»",fr:"Quand le bord du soleil [commence à] se lever, retarde la prière jusqu'à ce qu'il soit haut ; et quand le bord du soleil se couche, retarde la prière jusqu'à ce qu'il ait disparu.",ref:"Rapporté par al-Bukhārī (583) et Muslim (1897)"}]},
  {id:66, arNum:"الباب السادس والستون", arTitle:"باب قوله تعالى: {وما قدروا الله حق قدره}", frTitle:"La Parole d'Allah : « Ils n'ont pas estimé Allah comme Il devrait l'être »", summary:"Dernier chapitre du livre, il résume la cause fondamentale du shirk : les humains n'ont pas estimé Allah à Sa juste valeur. S'ils mesuraient véritablement la grandeur, la puissance et l'unicité d'Allah, ils ne Lui associeraient rien. Le verset dit : « Ils n'ont pas estimé Allah comme Il devrait l'être, alors que toute la terre sera dans Sa main au Jour de la Résurrection, et les cieux pliés dans Sa droite. Gloire à Lui ! Il est bien au-dessus de ce qu'ils Lui associent. » L'auteur conclut que la connaissance de la grandeur d'Allah et de Ses attributs de perfection est le rempart le plus solide contre le shirk.", verses:[{ar:"وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ وَالْأَرْضُ جَمِيعًا قَبْضَتُهُ يَوْمَ الْقِيَامَةِ وَالسَّمَاوَاتُ مَطْوِيَّاتٌ بِيَمِينِهِ ۚ سُبْحَانَهُ وَتَعَالَىٰ عَمَّا يُشْرِكُونَ",fr:"Ils n'ont pas estimé Allah comme Il devrait l'être, alors que toute la terre sera dans Sa main au Jour de la Résurrection, et les cieux pliés dans Sa droite. Gloire à Lui ! Il est bien au-dessus de ce qu'ils Lui associent.",ref:"Sourate al-Zumar (39:67)"}]}
];

// Sort and merge
CHAPTERS.sort((a, b) => a.id - b.id);

// For chapters where we only have basic data, fill in from REMAINING
const existingIds = new Set(CHAPTERS.map(c => c.id));
for (const ch of REMAINING) {
  if (!existingIds.has(ch.id)) {
    CHAPTERS.push(ch);
  }
}

CHAPTERS.sort((a, b) => a.id - b.id);
